import styled from 'styled-components';
import { useSpring, animated, config } from 'react-spring';
export const Container = styled(animated.div)`
position: fixed;
width: 100%;
bottom:0;
left: 0;

background: transparent;
z-index: 1;
& p{
    font-size: 0.5rem;

}



`;
